sql:
SELECT AVG(speed_download) AS typical_download_speed
FROM internet_plans
WHERE success_rate > 80;

SELECT *
FROM internet_plans
WHERE available_regions = 'Canada';

SELECT plan_id, date_recorded, average_speed 
FROM service_performance 
WHERE average_speed < 50 AND date_recorded > '2023-01-01';

SELECT * 
FROM internet_plans 
WHERE speed_download = (SELECT MAX(speed_download) FROM internet_plans);

external_knowledge:
- 'Let their subscription journey come to a halt' refers to subscriptions that are marked as 'cancelled'.;
- 'IDs of these dormant pathways' correspond to the `subscription_id` for the cancelled subscriptions.;
- 'In the order of their customer journey's start' refers to sorting by `customer_id` in ascending order, which often correlates with the sequence of customer onboarding.

"opened the doors to marketing whispers" implies customers have opted in for marketing communications (marketing_opt_in = 1);
"payment flowers are due to bloom" metaphorically refers to the payment due dates;
"order of their birth journey" means sorting by date of birth in ascending order.

sql:
SELECT customers.first_name, customers.last_name, subscriptions.start_date
FROM customers
JOIN subscriptions ON customers.customer_id = subscriptions.customer_id;

SELECT AVG(average_speed)
FROM service_performance
WHERE plan_id = 1;

